import{_ as s,c as l,o as i,a3 as a}from"./chunks/framework.LNmJnetQ.js";const b=JSON.parse('{"title":"Q&A - css","description":"","frontmatter":{"title":"Q&A - css"},"headers":[],"relativePath":"flow/fe/iq-css.md","filePath":"flow/fe/iq-css.md"}'),e={name:"flow/fe/iq-css.md"},t=a(`<details class="details custom-block"><summary>animation、transition、transform 有什么区别 ？</summary><ul><li>animation 属性用于创建复杂的动画序列</li><li>transition 属性用于在状态变化时平滑过渡</li><li>transform 属性用于对元素进行变形</li></ul></details><details class="details custom-block"><summary>怎么做移动端的样式适配 ？</summary><p>响应式设计（Responsive Design）：使用CSS媒体查询（Media Queries）来根据设备的特征（如屏幕宽度、高度、方向等）应用不同的样式。通过设置百分比宽度、最大宽度或相对单位（比如 rem）来确保元素相对于其容器的大小进行自适应。（媒体查询，百分比，vw/vh，rem）。</p><p>弹性布局（Flexbox）和网格布局（Grid）</p><p>移动端优先（Mobile-first）：首先定义移动端的样式，然后使用媒体查询逐渐添加更大屏幕上的样式，以确保基本功能在小屏幕上也能正常工作。</p></details><details class="details custom-block"><summary>如果使用CSS提高页面性能？</summary><ul><li>内联首屏关键CSS</li><li>异步加载CSS</li><li>资源压缩</li><li>合理使用选择器</li><li>减少使用昂贵的属性（box-shadow/ border-radius/ filter/ :nth-child）</li><li>不要使用@import</li></ul></details><details class="details custom-block"><summary>如何实现单行或多行文本溢出的省略样式？</summary><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>p {</span></span>
<span class="line"><span>  overflow: hidden;</span></span>
<span class="line"><span>  text-overflow: ellipsis;</span></span>
<span class="line"><span>  white-space: nowrap;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 多行</span></span>
<span class="line"><span>p {</span></span>
<span class="line"><span>  -webkit-line-clamp: 2;</span></span>
<span class="line"><span>  display: -webkit-box;</span></span>
<span class="line"><span>  -webkit-box-orient: vertical;</span></span>
<span class="line"><span>}</span></span></code></pre></div></details><details class="details custom-block"><summary>如何使用css完成视差滚动效果？</summary><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>section {</span></span>
<span class="line"><span>  height: 100vh;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>.g-img {</span></span>
<span class="line"><span>  background-image: url(...);</span></span>
<span class="line"><span>  background-attachment: fixed; // </span></span>
<span class="line"><span>  background-size: cover;</span></span>
<span class="line"><span>  background-position: center center;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>perspective: 1px;</span></span>
<span class="line"><span>transform-style: preserve-3d; </span></span>
<span class="line"><span>transform: translateZ(-1px);</span></span></code></pre></div></details><details class="details custom-block"><summary>怎么使用 CSS 如何画一个三角形</summary><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span></span></span></code></pre></div></details><details class="details custom-block"><summary>说说对 CSS 工程化的理解</summary><ul><li>宏观设计：CSS 代码如何组织、如何拆分、模块结构怎样设计？</li><li>编码优化：怎样写出更好的 CSS？</li><li>构建：如何处理我的 CSS，才能让它的打包结果最优？</li><li>可维护性：代码写完了，如何最小化它后续的变更成本？如何确保任何一个同事都能轻松接手？</li></ul><p>预处理器：Less、 Sass 等；重要的工程化插件： PostCss；Webpack loader 等 。</p></details><details class="details custom-block"><summary>怎么触发BFC，BFC有什么应用场景？</summary><p>position: absolute，元素定位将相对于上级元素中最近的一个relative、fixed、absolute，如果没有则相对于body；</p><p>position:fixed，正常来说是相对于浏览器窗口定位的，但是当元素祖先的 transform 属性非 none 时，会相对于该祖先进行定位。</p><p>块格式化上下文（Block Formatting Context，BFC） 是Web页面的可视CSS渲染的一部分，是块盒子的布局过程发生的区域，也是浮动元素与其他元素交互的区域。</p><p>触发条件：</p><ul><li>根元素，即 <code>&lt;html&gt;</code></li><li>浮动元素：float 值为 <code>left 、right</code></li><li>overflow 值不为 <code>visible</code>，即为 <code>auto、scroll、hidden</code></li><li>display 值为 <code>inline-block、table-cell、table-caption、table、inline-table、flex、inline-flex、grid、inline-grid</code></li><li>绝对定位元素：position 值为 <code>absolute、fixed</code></li></ul><p>应用：</p><ul><li>左列浮动（定宽或不定宽都可以），给右列开启 BFC（浮动盒的区域不会和 BFC 重叠）</li><li>防止外边距（margin）重叠</li><li>父子元素的外边距重叠</li></ul></details><details class="details custom-block"><summary>CSS 模块化的理解</summary><ul><li><p>BEM 命名规范: 块（block）、元素（element）、修饰符（modifier）</p></li><li><p>CSS Modules: 引入我们的 css 代码，代码中的每一个类名都是引入对象的一个属性，通过这种方式，即可在使用时明确指定所引用的 css 样式。在打包的时候会自动将类名转换成 hash 值，完全杜绝 css 类名冲突的问题。</p></li><li><p>CSS In JS: emotion</p></li></ul></details><details class="details custom-block"><summary>怎么实现样式隔离 ？</summary><ul><li>作用域样式（Scoped Styles）</li><li>CSS Modules</li><li>命名约定 BEM</li><li>CSS-in-JS emotion</li></ul></details><details class="details custom-block"><summary>盒子模型 ？</summary><p>一个盒子由四个部分组成：<code>content、padding、border、margin</code></p></details><details class="details custom-block"><summary>em/px/rem/vh/vw 这些单位有什么区别 ？</summary><ul><li>px：绝对单位，页面按精确像素展示</li><li>em：相对单位，基准点为父节点字体的大小，如果自身定义了font-size按自身来计算，整个页面内1em不是一个固定的值</li><li>rem：相对单位，可理解为root em, 相对根节点html的字体大小来计算</li><li>vh、vw：主要用于页面视口大小布局，在页面布局上更加方便简单</li></ul></details><details class="details custom-block"><summary>有哪些方式可以隐藏页面元素？有什么区别 ?</summary><ul><li><code>display:none</code>(元素不可见，不占据空间，无法响应点击事件)</li><li><code>visibility:hidden</code>(元素不可见，占据页面空间，无法响应点击事件)</li><li><code>opacity:0</code>(元素不可见，占据页面空间，可以响应点击事件)</li><li><code>position:absolute</code>(元素不可见，不影响页面布局)</li><li><code>clip-path</code>(<code>clip-path: polygon(0px 0px,0px 0px,0px 0px,0px 0px);</code>元素不可见，占据页面空间，无法响应点击事件)</li></ul></details><details class="details custom-block"><summary>css预编语言的理解，以及它们之间的区别?</summary><p>css预编语言是一种基于css的扩展语言，可以更加方便和高效地编写css代码。其主要作用是为css提供了变量、函数、嵌套、继承、混合等功能，以及更加易于维护和组织的代码结构。</p><p>优点：结构清晰，便于扩展。可以方便地屏蔽浏览器私有语法差异。封装对浏览器语法差异的重复处理，减少无意义的机械劳动。可以轻松实现多重继承。完全兼容css代码，可以方便地应用到老项目中。less 只是在css语法上做了扩展，所以老的css代码也可以与less代码一同编译。</p><p>常见的css预编语言有Sass、Less和Stylus等，它们之间的区别如下：</p><ul><li>语法不同: Sass和Less使用类似于css的语法规则，而Stylus则使用了更加简洁和灵活的缩进式语法。</li><li>变量定义方式不同：Sass使用$符号来定义变量，Less使用@符号，Stylus则直接使用变量名即可。</li><li>操作符和函数库不同：Sass和Less支持常见的操作符和函数库，例如运算符、颜色处理、字符串处理等，而Stylus的函数库更加强大，支持更多的特性和功能。</li><li>编译方式不同：Sass和Less都需要通过编译器进行编译，可以将预编译的代码转换成标准的css代码。而Stylus则可以直接在浏览器中解析和执行，可以动态调整样式和布局。</li></ul></details><details class="details custom-block"><summary>z-index属性在什么情况下会失效？</summary><ul><li>父元素position为relative时，子元素的z-index失效。解决：父元素position改为absolute或static；</li><li>元素没有设置position属性为非static属性。设置该元素的position属性为relative，absolute或是fixed中的一种；</li><li>元素在设置z-index的同时还设置了float浮动。解决：float去除，改为display：inline-block；</li></ul></details><details class="details custom-block"><summary>前端实现动画有哪些方式？</summary><ul><li>css3的transition 属性</li><li>css3的animation 属性</li><li>原生JS动画</li><li>使用canvas绘制动画</li><li>SVG动画</li><li>使用gif图片</li></ul></details><details class="details custom-block"><summary>CSS动画和JS实现的动画分别有哪些优缺点？</summary><p>多数显示器默认频率是60Hz，即1秒刷新60次，所以理论上最小间隔为1/60＊1000ms ＝ 16.7ms。</p><p>CSS动画: 优点：</p><ul><li>浏览器可以对动画进行优化</li><li>代码相对简单,性能调优方向固定</li><li>对于帧速表现不好的低版本浏览器，CSS3可以做到自然降级，而JS则需要撰写额外代码</li></ul><p>缺点：</p><ul><li>运行过程控制较弱,无法附加事件绑定回调函数</li><li>代码冗长，想用CSS实现稍微复杂一点动画,最后CSS代码都会变得非常笨重</li></ul><hr><p>js动画：</p><p>优点：</p><ul><li>控制能力很强, 可以在动画播放过程中对动画进行控制：开始、暂停、回放、终止、取消都是可以做到的。</li><li>动画效果比css3动画丰富,有些动画效果，比如曲线运动,冲击闪烁,视差滚动效果，只有js动画才能完成</li><li>CSS3有兼容性问题，而JS大多时候没有兼容性问题</li></ul><p>缺点：</p><ul><li>代码的复杂度高于CSS动画</li><li>js在浏览器的主线程中运行，而主线程中还有其它需要运行的JavaScript脚本、样式计算、布局、绘制任务等,对其干扰导致线程可能出现阻塞，从而造成丢帧的情况</li></ul></details><details class="details custom-block"><summary>js和css是如何影响DOM树构建的？</summary><p>JavaScript 会阻塞 DOM 生成，而css又会阻塞js的执行。</p></details><details class="details custom-block"><summary>absolute绝对定位，是相对于谁的定位？</summary><p>相对于最近的 非 static 祖先元素</p></details><details class="details custom-block"><summary>分析比较 opacity: 0、visibility: hidden、display: none 优劣和适用场景</summary><p>结构：</p><ul><li>display:none: 会让元素完全从渲染树中消失，渲染的时候不占据任何空间, 不能点击</li><li>visibility: hidden:不会让元素从渲染树消失，渲染元素继续占据空间，只是内容不可见，不能点击</li><li>opacity: 0: 不会让元素从渲染树消失，渲染元素继续占据空间，只是内容不可见，可以点击</li></ul><p>继承:</p><ul><li>display: none和opacity: 0：是非继承属性，子孙节点消失由于元素从渲染树消失造成，通过修改子孙节点属性无法显示。</li><li>visibility: hidden：是继承属性，子孙节点消失由于继承了hidden，通过设置visibility: visible;可以让子孙节点显式。</li></ul><p>性能:</p><ul><li>display:none : 修改元素会造成文档回流, 读屏器不会读取display: none元素内容，性能消耗较大</li><li>visibility:hidden : 修改元素只会造成本元素的重绘,性能消耗较少读屏器读取 visibility:hidden元素内容</li><li>opacity: 0 ：修改元素会造成重绘，性能消耗较少</li></ul></details><details class="details custom-block"><summary>CSS优化、提高性能的方法有哪些？</summary><ul><li>避免过度约束</li><li>避免后代选择符</li><li>避免链式选择符</li><li>使用紧凑的语法</li><li>避免不必要的命名空间</li><li>避免不必要的重复</li><li>最好使用表示语义的名字。一个好的类名应该是描述他是什么而不是像什么</li><li>避免！important，可以选择其他选择器</li><li>尽可能的精简规则，你可以合并不同类里的重复规则</li></ul></details><details class="details custom-block"><summary>前端项目中为什么要初始化CSS样式？</summary><p>因为浏览器的兼容问题，不同浏览器对标签的默认值是不同的，如果没有对浏览器的CSS初始化，会造成相同页面在不同浏览器的显示存在差异。</p></details><details class="details custom-block"><summary>硬件加速的原理是什么？</summary><p>一个完整的渲染步骤大致可总结为如下：</p><ul><li>渲染进程将HTML内容转换为能够读懂的DOM树结构。</li><li>渲染引擎将CSS样式表转化为浏览器可以理解的 styleSheets ，计算出DOM节点的样式。</li><li>创建布局树，并计算元素的布局信息。</li><li>对布局树进行分层，并生成分层树。</li><li>为每个图层生成绘制列表，并将其提交到合成线程。</li><li>合成线程将图层分成图块，并在光栅化线程池中将图块转换成位图。</li><li>合成线程发送绘制图块命令DrawQuad给浏览器进程。</li><li>浏览器进程根据DrawQuad消息生成页面，并显示到显示器上</li></ul><p>硬件加速，直观上说就是依赖 GPU 实现图形绘制加速，软硬件加速的区别主要是图形的绘制究竟是 GPU 来处理还是 CPU，如果是 GPU，就认为是硬件加速绘制，反之，则为软件绘制。</p><p>常用的硬件加速方法有：</p><ul><li>最常用的方式：translate3d、translateZ</li><li>opacity 属性/过渡动画（需要动画执行的过程中才会创建合成层，动画没有开始或结束后元素还会回到之前的状态）</li><li>will-change属性（这个知识点比较冷僻），一般配合 opacity 与 translate 使用（而且经测试，除了上述可以引发硬件加速的属性外，其它属性并不会变成复合层），作用是提前告诉浏览器要变化，这样浏览器会开始做一些优化工作（这个最好用完后就释放）<code>&lt;video&gt;、&lt;iframe&gt;、&lt;canvas&gt;、&lt;webgl&gt;</code>等元素</li><li>其它，譬如以前的 flash 插件</li></ul><p>当然，有的时候我们想强制触发硬件渲染，就可以通过上面的属性，比如:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>will-change: transform;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>transform:translate3d(0, 0, 0);</span></span></code></pre></div></details><details class="details custom-block"><summary>css匹配规则？</summary><ul><li>css样式匹配规则： 从右到左进行匹配，从底层向上查找，增加匹配效率</li><li>css文件匹配顺序： 匹配css文件越往后定义的规则</li></ul></details><details class="details custom-block"><summary>页面导入样式时，使用link和@import有什么区别？</summary><p>link属于HTML标签，而@import是css提供的；</p><p>页面被加载时，link会同时被加载，而@import引用的css会等到页面被加载完再加载；</p><p>@import只在IE5以上才能识别，而link是XHTML标签，无兼容问题；</p><p>link方式的样式的权重高于@import的权重。</p></details><details class="details custom-block"><summary>为什么会出现浮动？什么时候需要清除浮动？清除浮动的方式有哪些？</summary><p>浮动元素碰到包含它的边框或者浮动元素的边框停留。由于浮动元素不在文档流中，所以文档流的块框表现得就像浮动框不存在一样。浮动元素会漂浮在文档流的块框上。</p><p>浮动带来的问题：</p><ul><li>父元素的高度无法被撑开，影响与父元素同级的元素</li><li>与浮动元素同级的非浮动元素（内联元素）会跟随其后</li><li>若非第一个元素浮动，则该元素之前的元素也需要浮动，否则会影响页面显示的结构。</li></ul><p>清除浮动的方式：</p><ul><li>父级div定义height</li><li>最后一个浮动元素后加空div标签 并添加样式clear:both。</li><li>包含浮动元素的父标签添加样式overflow为hidden或auto。</li><li>父级div定义zoom</li></ul></details><details class="details custom-block"><summary>box-sizing属性值有什么用？</summary><p>用来控制元素的盒子模型的解析模式，默认为content-box</p><ul><li>context-box：W3C的标准盒子模型，设置元素的 height/width 属性指的是content部分的高/宽</li><li>border-box：IE传统盒子模型。设置元素的height/width属性指的是border + padding + content部分的高/宽</li></ul></details>`,27),n=[t];function p(c,o,d,m,u,r){return i(),l("div",null,n)}const S=s(e,[["render",p]]);export{b as __pageData,S as default};
